class Solution {
    public String crackSafe(int n, int k) {
        StringBuilder sb = new StringBuilder();
        Set<String> seen = new HashSet<>();
        dfs(sb, seen, n, k);
        return sb.toString();
    }
    private void dfs(StringBuilder sb, Set<String> seen, int n, int k) {
        if (sb.length() == n) {
            return;
        }
        for (int i = 0; i < k; i++) {
            String next = sb.toString() + i;
            if (!seen.contains(next.substring(sb.length()))) {
                seen.add(next.substring(sb.length()));
                sb.append(i);
                dfs(sb, seen, n, k);
                sb.deleteCharAt(sb.length() - 1);
            }
        }
    }
}
